INSERT INTO "public"."landing_pages" ("id", "slug", "title", "theme", "content", "images", "pixels", "is_active", "created_at", "updated_at", "advantages", "reviews", "benefits", "colors", "styles", "main_title", "description", "main_image", "secondary_image", "button_text", "survey_text") VALUES (13, 'mobile-sales', 'Это тестовое название mobile-sales', null, '{}', '[]', '["23213123123213"]', true, '2025-12-26 10:40:29.358774+00', '2026-03-10 06:18:56.281333+00', '[{"title":"1","description":"2"}]', '[{"text":"23213123","image":"https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/categories/ef5f2f34-eda8-48a2-80d7-bd90a184b915.png"}]', '["Какое-то приимущество"]', '{"button":"#4caf50","header":"#1a1a1a","textColor":"#1a1a1a","background":"#ffffff","buttonHover":"#45a049","bodyBackground":"#ffffff"}', '{}', 'Это тестовое название Это тестовое название', 'Это тестовое название Это тестовое название', 'https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/categories/71668395-aa31-4644-bc37-4575c10d1873.png', 'https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/products/b7cfa580-fa67-44b0-83ab-8a4ae285326a.png', 'Узнать цену', 'какой-то текст'), (14, 'laptop-phone', 'Ноут + смартфон', null, '{}', '[]', '["D5EO5ABC77UF0FHAVGE0"]', true, '2026-01-05 12:39:57.500543+00', '2026-02-11 18:22:44.481875+00', '[{"title":"Рассрочка с доступными платежами","description":"Срок рассрочки до 5 лет без переплат и 1-го платежа. Не нужны справки о доходах и поручители. Оформление онлайн за 10 минут"},{"title":"Оптовые цены","description":"Мы сотрудничаем с заводами-производителями, поэтому продаем технику без наценок и переплат"},{"title":"Гарантия до 5 лет","description":"На все товары у нас есть расширенная гарантия от магазина. У нас собственный сервисный центр и большой склад запчастей"}]', '[{"text":"Долго искала ноутбук по нормальной цене, везде выходило очень дорого. Здесь понравились условия - рассрочка с небольшими платежами и без лишних переплат. Доставили бесплатно, всё аккуратно и вовремя. Приятно удивил подарок - телефон. В целом покупкой довольна, магазин могу рекомендовать.\\n\\nОльга, г. Слуцк","image":"https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/b651ddca-20fb-4650-8cfe-affa801bacae.JPG"},{"text":"Покупал ноутбук, выбирал долго, цены сейчас кусаются. Здесь предложили рассрочку с небольшими ежемесячными платежами, без лишних условий. Оформление прошло быстро, доставку сделали бесплатно. В комплекте ещё был подарок - телефон, что стало приятным бонусом. Впечатления положительные, магазин оставил хорошее впечатление.\\n\\nИван, д. Агаповка","image":"https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/17f51ba3-4aac-4f7b-b290-daa7bb729166.png"},{"text":"С ноутбуком тянули до последнего, всё надеялись найти вариант подешевле. В этом магазине устроили условия: рассрочка без нагрузки, платежи небольшие, доставили бесплатно. Всё привезли в целости, проверили при мне. К заказу дали телефон в подарок, что было неожиданно, но приятно. В целом покупкой доволен, могу сказать - магазин надёжный.\\n\\nВиктор, г.Солигорск","image":"https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/717a9953-99e0-46d0-9f7e-8cb405c3292c.jpg"}]', '["Рассрочка до 5 лет","Без первого взноса и переплат","Смартфон в подарок каждому клиенту"]', '{"button":"#FF6A3D","header":"#1A73E8","textColor":"#222222","background":"#F7F8FA","buttonHover":"#FF6A3D","bodyBackground":"#FFF7F0"}', '{}', 'НОУТБУКИ В РАССРОЧКУ + СМАРТФОН В ПОДАРОК ДАРИМ КАЖДОМУ КЛИЕНТУ', 'какое-то описание', 'https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/0a8220ae-31b8-431e-8242-1dedbe311711.png', 'https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/fa1fa415-ff46-4750-9a27-fa70173ddde0.jpg', 'Узнать цену', 'Ответьте на 4 вопроса и мы вышлем график платежей с учетом скидки -50% и подарка'), (15, 'tele-phone', 'Телевизор + смартфон', null, '{}', '[]', '["D5G0NFRC77U4NSOIFK70"]', true, '2026-01-08 19:45:35.923579+00', '2026-02-04 20:11:45.057269+00', '[{"title":"Рассрочка с доступными платежами","description":"Срок рассрочки до 5 лет без переплат и 1-го платежа. Не нужны справки о доходах и поручители. Оформление онлайн за 10 минут"},{"title":"Гарантия до 5 лет","description":"На все товары у нас есть расширенная гарантия от магазина. У нас собственный сервисный центр и большой склад запчастей"},{"title":"Все телевизоры по оптовой цене","description":"Мы сотрудничаем с заводами-производителями, поэтому продаем все модели без наценок и переплат"}]', '[{"text":"Долго искала телевизор по нормальной цене, везде выходило очень дорого. Здесь понравились условия - рассрочка с небольшими платежами и без лишних переплат. Доставили бесплатно, всё аккуратно и вовремя. Приятно удивил подарок - телефон. В целом покупкой довольна, магазин могу рекомендовать.\\n","image":"https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/8d96e9c4-3ad5-4cb0-9905-17f6db86db9f.jpg"},{"text":"Покупал телевизор, выбирал долго, цены сейчас кусаются. Здесь предложили рассрочку с небольшими ежемесячными платежами, без лишних условий. Оформление прошло быстро, доставку сделали бесплатно. В комплекте ещё был подарок - телефон, что стало приятным бонусом. Впечатления положительные, магазин оставил хорошее впечатление.\\n","image":"https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/8129df2a-240f-4889-a145-861154048b96.jpeg"},{"text":"С телевизором тянули до последнего, всё надеялись найти вариант подешевле. В этом магазине устроили условия: рассрочка без нагрузки, платежи небольшие, доставили бесплатно. Всё привезли в целости, проверили при мне. К заказу дали телефон в подарок, что было неожиданно, но приятно. В целом покупкой довольна, могу сказать - магазин надёжный.\\n\\nВиктория, г.Солигорск","image":"https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/dc7c91ec-0b05-48b4-a98c-4f05f27bced2.jpeg"}]', '["Рассрочка с платежами от 39 рублей","До 5 лет и без 1-го взноса","Бесплатная доставка","Смартфон в подарок"]', '{"button":"#1E63D8","header":"#1B1B1B","textColor":"#2B2B2B","background":"#f0f0f0","buttonHover":"#1E63D8","bodyBackground":"#FFFFFF"}', '{}', 'ПОКУПАЙТЕ ТЕЛЕВИЗОР В РАССРОЧКУ И ЗАБИРАЙТЕ ТЕЛЕФОН В ПОДАРОК', null, 'https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/3d4d0b55-3a07-45ee-bf56-4610b7ea351e.png', 'https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/fa1fa415-ff46-4750-9a27-fa70173ddde0.jpg', 'Узнать цену', 'Ответьте на 4 вопроса и мы вышлем график платежей с учетом скидки -50% и подарка'), (16, 'tele-sound', 'Телевизор + саундбар', null, '{}', '[]', '["D5GLL73C77UEHQ1H6SH0","D61QFK3C77U3UMFCUM3G"]', true, '2026-01-09 19:45:00.885486+00', '2026-02-04 20:11:54.485875+00', '[{"title":"Рассрочка с доступными платежами","description":"Срок рассрочки до 5 лет без переплат и 1-го платежа. Не нужны справки о доходах и поручители. Оформление онлайн за 10 минут"},{"title":"Гарантия до 5 лет","description":"На все товары у нас есть расширенная гарантия от магазина. У нас собственный сервисный центр и большой склад запчастей"},{"title":"Все телевизоры по оптовой цене","description":"Мы сотрудничаем с заводами-производителями, поэтому продаем все модели без наценок и переплат"}]', '[]', '["Рассрочка до 5 лет и без 1-го взноса","Доступные платежи от 49 рублей","Бесплатная доставка в течении 5 дней","Звуковая система \\"Саундбар\\" в подарок"]', '{"button":"#e6d200","header":"#4caf50","textColor":"#1a1a1a","background":"#ffffff","buttonHover":"#e6d200","bodyBackground":"#ffffff"}', '{}', 'САУНДБАР В ПОДАРОК ПРИ ПОКУПКЕ ТЕЛЕВИЗОРА В РАССРОЧКУ', null, 'https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/8b78ba1a-df43-4a55-a15a-dfb1c38463de.png', 'https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/42b1c6e2-f988-420e-bc3b-024e6685c03b.png', 'ПОЛУЧИТЬ РАСЧЕТ', 'Ответьте на 4 вопроса и мы вышлем график платежей с учетом скидки -50% и подарка'), (17, 'phone-present', 'Телефон + телефон', null, '{}', '[]', '["D5J9CKRC77U666PPLOCG","D63RP23C77U555CM6PF0"]', true, '2026-01-13 18:54:45.583634+00', '2026-02-07 22:28:50.995702+00', '[{"title":"Рассрочка с доступными платежами","description":"Срок рассрочки до 5 лет без переплат и 1-го платежа. Не нужны справки о доходах и поручители. Оформление онлайн за 10 минут"},{"title":"Оптовые цены","description":"Мы сотрудничаем с заводами-производителями, поэтому продаем смартфоны без наценок и переплат"},{"title":"Гарантия до 5 лет","description":"На все товары мы даем расширенную гарантию от магазина. У нас собственный сервисный центр и большой склад запчастей"}]', '[{"text":"Долго искала магазин, где можно купить хороший телефон по нормальной цене, везде выходило очень дорого. Здесь понравились условия - рассрочка с небольшими платежами и без лишних переплат. Доставили бесплатно, всё аккуратно и вовремя. Приятно удивил подарок - телефон. В целом покупкой довольна, магазин могу рекомендовать.\\n","image":"https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/dc7c91ec-0b05-48b4-a98c-4f05f27bced2.jpeg"},{"text":"Покупал тут телефон. Выбирал по цене, они сейчас кусаются и сильно отличаются в разных магазинах. Тут предложили рассрочку с хорошими платежами и без лишних переплат. Оформление прошло быстро, доставку сделали бесплатно. В комплекте ещё был подарок - второй телефон, что стало приятным бонусом. Покупкой доволен. А сын еще больше, второй телефон подарили ему. \\n","image":"https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/8129df2a-240f-4889-a145-861154048b96.jpeg"},{"text":"Самое главное на что я смотрела - это условия. Купила у вас, потому что предложили самые лучшие платежи. Плачу рассрочку без проблем. Доставили быстро и бесплатно. Всё привезли в целости, проверили при мне. А то , что дали второй телефон в подарок, было неожиданно. Не думала, что это правда. В целом покупкой довольна, могу сказать - магазин надёжный. Рекомендую\\n","image":"https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/8d96e9c4-3ad5-4cb0-9905-17f6db86db9f.jpg"}]', '["Рассрочка до 5 лет","Без первого взноса и переплат","Смартфон в подарок каждому клиенту"]', '{"button":"#e6d200","header":"#b400cc","textColor":"#1a1a1a","background":"#fffafa","buttonHover":"#e6d200","bodyBackground":"#ffffff"}', '{}', 'ПОКУПАЙ ТЕЛЕФОН В РАССРОЧКУ, А ВТОРОЙ МЫ ПОДАРИМ БЕСПЛАТНО', null, 'https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/74b02474-d820-437d-83d3-f0aa727cd55d.png', 'https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/fa1fa415-ff46-4750-9a27-fa70173ddde0.jpg', 'Узнать цену', 'Ответьте на 4 вопроса и мы вышлем график платежей с учетом скидки -50% и подарка'), (18, 'coffee-machine', 'Кофемашина + кофе', null, '{}', '[]', '["D5OJCABC77UBONMAU6CG"]', true, '2026-01-21 20:25:46.868202+00', '2026-01-21 20:52:57.79883+00', '[{"title":"Рассрочка с доступными платежами","description":"Срок рассрочки до 5 лет без переплат и 1-го платежа. Не нужны справки о доходах и поручители. Оформление онлайн за 10 минут"},{"title":"Гарантия до 5 лет","description":"Каждый клиент получает расширенную гарантию от магазина. У нас прямой импорт и собственный сервисный центр с большим складом запчастей"},{"title":"Продаем кофемашины по оптовой цене","description":"Мы сотрудничаем с заводами-производителями, поэтому продаем все модели без наценок и переплат"}]', '[{"text":"Я самый настоящий кофеман, но всегда жалела деньги на хорошую кофемашину. Долго искала хорошие варианты по нормальной цене, везде выходило очень дорого. Здесь понравились условия - рассрочка с небольшими платежами и без лишних переплат. Доставили бесплатно, всё аккуратно и вовремя. В целом покупкой довольна, магазин могу рекомендовать.\\n","image":"https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/dc7c91ec-0b05-48b4-a98c-4f05f27bced2.jpeg"},{"text":"Спасибо, теперь каждое утро балдеем с женой. Всегда хотели домой небольшую и простую кофемашину, которая сама будет делать кофе и не надо взбивать молоко. Купили идеальный вариант. Простая в использовании, легкая в обслуживании. Воду залил, кофе насыпал и через минуту кофе готов. Отдельное спасибо за условия. Рассрочка с такими платежами просто смех, даже не чувствуем их. Про ваш магазин уже рассказал всем друзьям","image":"https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/717a9953-99e0-46d0-9f7e-8cb405c3292c.jpg"}]', '["Рассрочка до 5 лет и без 1-го взноса","Доступный платеж 49 рублей в месяц","Бесплатная доставка в течении 5 дней"]', '{"button":"#FF6A3D","header":"#1A73E8","textColor":"#222222","background":"#F7F8FA","buttonHover":"#FF6A3D","bodyBackground":"#FFF7F0"}', '{}', '2 КГ КОФЕ В ПОДАРОК ПРИ ПОКУПКЕ КОФЕМАШИНЫ В РАССРОЧКУ', null, 'https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/bc3e98f5-a6e0-4726-a23a-98c34880ec9e.png', 'https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/87ee4b57-a8e9-4107-ac7a-ccc3a69512c2.png', 'Оформить заказ', 'Ответьте на 4 вопроса и мы вышлем график платежей с учетом скидки -50% и подарка'), (19, 'phone-watch', 'Телефон + смарт часы', null, '{}', '[]', '["D5TMIABC77U6BSHUKT20","D61P72JC77U6BSHURLC0","D62TVG3C77UC1EV4BJSG","D63RMTRC77U5GADIJ4EG","D65JFC3C77U25FF4ERF0"]', true, '2026-01-29 13:25:20.451681+00', '2026-02-10 13:52:45.641624+00', '[{"title":"Рассрочка с доступными платежами","description":"Срок рассрочки до 5 лет без переплат и 1-го платежа. Не нужны справки о доходах и поручители. Оформление онлайн за 10 минут"},{"title":"Оптовые цены","description":"Мы сотрудничаем с заводами-производителями, поэтому продаем смартфоны без наценок и переплат"},{"title":"Гарантия до 5 лет","description":"На все товары мы даем расширенную гарантию от магазина. У нас собственный сервисный центр и большой склад запчастей"}]', '[{"text":"Долго искала магазин, где можно купить хороший телефон по нормальной цене, везде выходило очень дорого. Здесь понравились условия - рассрочка с небольшими платежами и без лишних переплат. Доставили бесплатно, всё аккуратно и вовремя. Приятно удивил подарок - умные часы. В целом покупкой довольна, магазин буду рекомендовать.\\n","image":"https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/b651ddca-20fb-4650-8cfe-affa801bacae.JPG"},{"text":"Покупал тут телефон. Выбирал по цене, они сейчас кусаются и сильно отличаются в разных магазинах. Вы предложили рассрочку с самыми низкими платежами и без лишних переплат. Оформление прошло быстро, доставку сделали бесплатно. Подарок смарт часы вообще крутые, сыну очень понравились. Покупкой доволен. А сын еще больше!\\n","image":"https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/717a9953-99e0-46d0-9f7e-8cb405c3292c.jpg"},{"text":"Мне нужен был самый обычный телефоны и главное на что я смотрела - это условия. Купила у вас, потому что предложили самые низкие платежи. Плачу рассрочку без проблем. Доставили быстро и бесплатно. Всё привезли в целости, проверили при мне. Умные часы тоже понравились. Считаю шаги, слышу звонки и даже давление измеряю. В целом покупкой довольна, могу сказать - магазин надёжный. Рекомендую\\n","image":"https://beagudoboagjuwltklis.supabase.co/storage/v1/object/public/images/landings/8d96e9c4-3ad5-4cb0-9905-17f6db86db9f.jpg"}]', '["Рассрочка до 5 лет без 1-го платежа","Доступные платежи от 29 рублей","Мы одобряем рассрочку более 95% клиентов","Начало оплаты со 2-го месяца","Бесплатная доставка прямо до двери ","Смарт-часы в подарок каждому клиенту 🎁"]', '{"button":"#ffbb00","header":"#6933ff","textColor":"#1a1a1a","background":"#feffe0","but